import React, { useState, useEffect } from 'react';
import { Package, Bike, Home } from 'lucide-react';

const SeguimientoPedido = ({ pedido, onFinalizar }) => {
  const [fase, setFase] = useState(1);
  const [porcentajeCamino, setPorcentajeCamino] = useState(0);

  useEffect(() => {
    // 1. Simulación del avance de la moto (0% a 100%)
    const intervalo = setInterval(() => {
      setPorcentajeCamino(prev => {
        if (prev >= 100) {
          clearInterval(intervalo);
          return 100;
        }
        return prev + 1;
      });
    }, 150); // Completa el recorrido en aprox 15 segundos

    // 2. Control de Fases de texto
    // Fase 1: Preparando (0s - 2s)
    // Fase 2: En camino (2s - 15s)
    const t1 = setTimeout(() => setFase(2), 2000); 

    // Fase 3: Entregado (15s)
    const t2 = setTimeout(() => {
      setFase(3);
      // Auto-finalizar y mover al historial 3 segundos después de llegar
      setTimeout(() => { 
        if (onFinalizar) onFinalizar(pedido.id); 
      }, 3000);
    }, 15000);

    return () => {
      clearInterval(intervalo);
      clearTimeout(t1);
      clearTimeout(t2);
    };
  }, [pedido.id, onFinalizar]);

  return (
    <div style={card}>
      <div style={header}>
        <div>
          <strong style={{ display: 'block', fontSize: '1.1rem' }}>Pedido #{pedido.id.slice(-6)}</strong>
          <small style={{ color: '#64748b' }}>📍 {pedido.direccion}</small>
        </div>
        <div style={estadoBadge(fase)}>
          {fase === 1 ? 'El local está preparando tu pedido' : 
           fase === 2 ? 'El cadete está enviando tu pedido' : 
           '¡Entregamos tu pedido!'}
        </div>
      </div>

      <div style={pistaContenedor}>
        <div style={iconoSucursal}><Package size={24} /></div>
        
        <div style={lineaGris}>
          {/* Línea naranja que sigue a la moto */}
          <div style={{ ...lineaNaranja, width: `${porcentajeCamino}%` }} />
          
          {/* Moto con desplazamiento dinámico */}
          <div style={{ ...motoContenedor, left: `${porcentajeCamino}%` }}>
            <Bike size={28} color="#e67e22" fill="#fff" />
            {fase === 2 && <div style={humoAnimado}></div>}
          </div>
        </div>

        <div style={{...iconoCasa, color: fase === 3 ? '#e67e22' : '#cbd5e1'}}><Home size={24} /></div>
      </div>

      <div style={footerInfo}>
        <span>Distancia: <strong>{pedido.distancia || '1.5'} km</strong></span>
        <span>
            {fase === 3 
                ? <strong style={{color: '#27ae60'}}>✨ ¡Disfruta tu compra!</strong> 
                : <span>Llegada estimada: <strong>{Math.max(1, 10 - Math.round(porcentajeCamino/10))} min</strong></span>
            }
        </span>
      </div>
    </div>
  );
};

// --- ESTILOS ---
const card = { background: 'white', padding: '25px', borderRadius: '24px', border: '1px solid #e2e8f0', marginBottom: '20px', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' };
const header = { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '30px' };
const estadoBadge = (fase) => ({
  padding: '8px 16px',
  borderRadius: '12px',
  fontSize: '0.85rem',
  fontWeight: 'bold',
  textAlign: 'right',
  maxWidth: '200px',
  background: fase === 3 ? '#dcfce7' : fase === 2 ? '#dbeafe' : '#fef3c7',
  color: fase === 3 ? '#166534' : fase === 2 ? '#1e40af' : '#92400e'
});

const pistaContenedor = { display: 'flex', alignItems: 'center', gap: '15px', height: '60px', margin: '20px 0', position: 'relative' };
const lineaGris = { flex: 1, height: '8px', background: '#f1f5f9', borderRadius: '10px', position: 'relative' };
const lineaNaranja = { position: 'absolute', height: '100%', background: '#e67e22', borderRadius: '10px', transition: 'width 0.2s linear' };
const motoContenedor = { position: 'absolute', top: '-12px', transform: 'translateX(-50%)', transition: 'left 0.2s linear', display: 'flex', flexDirection: 'column', alignItems: 'center' };
const iconoSucursal = { color: '#94a3b8' };
const iconoCasa = { transition: 'color 0.5s ease' };
const footerInfo = { marginTop: '20px', display: 'flex', justifyContent: 'space-between', fontSize: '0.85rem', color: '#475569', borderTop: '1px solid #f1f5f9', paddingTop: '15px' };
const humoAnimado = { width: '4px', height: '4px', background: '#cbd5e1', borderRadius: '50%', marginTop: '4px', boxShadow: '-6px 0px 0px #e2e8f0' };

export default SeguimientoPedido;
